CREATE OR REPLACE PROCEDURE hello_oracle AS
BEGIN
  DBMS_OUTPUT.PUT_LINE('Hello Oracle');
END;
/
EXEC hello_oracle;

CREATE OR REPLACE PROCEDURE get_emp_details(p_no IN NUMBER) AS
  v_name EMP.ENAME%TYPE; 
  v_sal EMP.SAL%TYPE;
BEGIN
  SELECT ENAME, SAL INTO v_name, v_sal FROM EMP WHERE EMPNO = p_no;
  DBMS_OUTPUT.PUT_LINE('Name: ' || v_name || ' | Salary: ' || v_sal);
END;
/
EXEC get_emp_details(7839);

CREATE OR REPLACE PROCEDURE dept_employees(p_dept IN NUMBER) AS
BEGIN
  FOR r IN (SELECT ENAME FROM EMP WHERE DEPTNO = p_dept) LOOP
    DBMS_OUTPUT.PUT_LINE(r.ename);
  END LOOP;
END;
/
EXEC dept_employees(10);

CREATE OR REPLACE PROCEDURE earners_more_than(p_sal IN NUMBER) AS
BEGIN
  FOR r IN (SELECT ENAME, SAL FROM EMP WHERE SAL > p_sal) LOOP
    DBMS_OUTPUT.PUT_LINE(r.ename || ' (' || r.sal || ')');
  END LOOP;
END;
/
EXEC earners_more_than(3000);

CREATE OR REPLACE PROCEDURE get_sal_out(p_no IN NUMBER, p_sal OUT NUMBER) AS
BEGIN
  SELECT SAL INTO p_sal FROM EMP WHERE EMPNO = p_no;
END;
/
DECLARE
  v_s NUMBER;
BEGIN
  get_sal_out(7788, v_s);
  DBMS_OUTPUT.PUT_LINE('Salary: ' || v_s);
END;

CREATE OR REPLACE PROCEDURE hike_sal(p_sal IN OUT NUMBER) AS
BEGIN
  p_sal := p_sal * 1.10;
END;
/
DECLARE
  v_val NUMBER := 1000;
BEGIN
  hike_sal(v_val);
  DBMS_OUTPUT.PUT_LINE('Updated: ' || v_val);
END;

CREATE OR REPLACE PROCEDURE insert_emp(p_id NUMBER, p_name VARCHAR2) AS
BEGIN
  INSERT INTO EMP (EMPNO, ENAME) VALUES (p_id, p_name);
  DBMS_OUTPUT.PUT_LINE('Employee Added.');
END;

CREATE OR REPLACE PROCEDURE update_emp_sal(p_id NUMBER, p_sal NUMBER) AS
BEGIN
  UPDATE EMP SET SAL = p_sal WHERE EMPNO = p_id;
  DBMS_OUTPUT.PUT_LINE('Salary Updated.');
END;

CREATE OR REPLACE PROCEDURE delete_emp(p_id NUMBER) AS
BEGIN
  DELETE FROM EMP WHERE EMPNO = p_id;
  DBMS_OUTPUT.PUT_LINE('Employee Deleted.');
END;

CREATE OR REPLACE PROCEDURE global_hike(p_pct NUMBER) AS
BEGIN
  UPDATE EMP SET SAL = SAL + (SAL * p_pct / 100);
  DBMS_OUTPUT.PUT_LINE(SQL%ROWCOUNT || ' rows updated');
END;

CREATE OR REPLACE PROCEDURE transfer_emp(p_id NUMBER, p_new_dept NUMBER) AS
BEGIN
  UPDATE EMP SET DEPTNO = p_new_dept WHERE EMPNO = p_id;
  DBMS_OUTPUT.PUT_LINE('Transfer Successful.');
END;

CREATE OR REPLACE PROCEDURE top_5_emps AS
  CURSOR c_top IS SELECT ENAME, SAL FROM EMP ORDER BY SAL DESC;
  v_c NUMBER := 0;
BEGIN
  FOR r IN c_top LOOP
    DBMS_OUTPUT.PUT_LINE(r.ename || ': ' || r.sal);
    v_c := v_c + 1;
    EXIT WHEN v_c = 5;
  END LOOP;
END;

CREATE OR REPLACE PROCEDURE transaction_test AS
BEGIN
  UPDATE EMP SET SAL = SAL + 10;
  COMMIT;
  DBMS_OUTPUT.PUT_LINE('Transaction Managed.');
EXCEPTION
  WHEN OTHERS THEN 
    ROLLBACK;
    DBMS_OUTPUT.PUT_LINE('Transaction Rolled Back.');
END;

CREATE OR REPLACE FUNCTION get_square(n NUMBER) RETURN NUMBER AS
BEGIN
  RETURN n * n;
END;
/
SELECT get_square(5) FROM DUAL;

CREATE OR REPLACE FUNCTION find_sal(p_no NUMBER) RETURN NUMBER AS
  v_s NUMBER;
BEGIN
  SELECT SAL INTO v_s FROM EMP WHERE EMPNO = p_no;
  RETURN v_s;
END;

CREATE OR REPLACE FUNCTION count_all_emps RETURN NUMBER AS
  v_c NUMBER;
BEGIN
  SELECT COUNT(*) INTO v_c FROM EMP;
  RETURN v_c;
END;

CREATE OR REPLACE FUNCTION get_max_sal RETURN NUMBER AS
  v_m NUMBER;
BEGIN
  SELECT MAX(SAL) INTO v_m FROM EMP;
  RETURN v_m;
END;

CREATE OR REPLACE FUNCTION get_dname(p_dno NUMBER) RETURN VARCHAR2 AS
  v_n VARCHAR2(20);
BEGIN
  SELECT DNAME INTO v_n FROM DEPT WHERE DEPTNO = p_dno;
  RETURN v_n;
END;

CREATE OR REPLACE FUNCTION calc_bonus(p_sal NUMBER) RETURN NUMBER AS
BEGIN
  RETURN p_sal * 0.15;
END;

CREATE OR REPLACE FUNCTION check_grade(p_sal NUMBER) RETURN CHAR AS
BEGIN
  IF p_sal > 4000 THEN RETURN 'A';
  ELSIF p_sal > 2000 THEN RETURN 'B';
  ELSE RETURN 'C'; END IF;
END;
